from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    index_file = Path(index_path)
    index_dir = index_file.parent if index_file.parent.name else Path.cwd()

    # Find metadata file
    meta_path = index_dir / f"{index_file.name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Leann metadata file not found at {meta_path}")

    # Load metadata to find passages file
    with open(meta_path, encoding="utf-8") as f:
        meta = json.load(f)

    # Find passages file - try several patterns
    passages_file = None

    # Check if specified in metadata
    if "passages_source_file" in meta:
        pf = Path(meta["passages_source_file"])
        if not pf.is_absolute():
            pf = index_dir / pf
        if pf.exists():
            passages_file = pf

    # Try default patterns if not found
    if not passages_file:
        for pattern in [f"{index_file.stem}.jsonl", f"{index_file.stem}.passages.jsonl", "passages.jsonl"]:
            candidate = index_dir / pattern
            if candidate.exists():
                passages_file = candidate
                break

    if not passages_file:
        raise FileNotFoundError(f"Passages file not found for index {index_path}")

    # Collect statistics
    total_passages = 0
    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    with open(passages_file, encoding="utf-8") as f:
        for line in f:
            if not line.strip():
                continue
            try:
                passage = json.loads(line)
                total_passages += 1

                if "metadata" in passage:
                    for field, value in passage["metadata"].items():
                        metadata_fields.add(field)
                        field_value_counts[field][str(value)] += 1
            except json.JSONDecodeError:
                continue

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(list(metadata_fields)),
        "field_value_counts": {k: dict(v) for k, v in field_value_counts.items()}
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    index_file = Path(index_path)
    index_dir = index_file.parent if index_file.parent.name else Path.cwd()

    # Find metadata file
    meta_path = index_dir / f"{index_file.name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Leann metadata file not found at {meta_path}")

    # Load metadata to find passages file
    with open(meta_path, encoding="utf-8") as f:
        meta = json.load(f)

    # Find passages file
    passages_file = None

    if "passages_source_file" in meta:
        pf = Path(meta["passages_source_file"])
        if not pf.is_absolute():
            pf = index_dir / pf
        if pf.exists():
            passages_file = pf

    if not passages_file:
        for pattern in [f"{index_file.stem}.jsonl", f"{index_file.stem}.passages.jsonl", "passages.jsonl"]:
            candidate = index_dir / pattern
            if candidate.exists():
                passages_file = candidate
                break

    if not passages_file:
        raise FileNotFoundError(f"Passages file not found for index {index_path}")

    # Analyze coverage
    total_passages = 0
    passages_with_all_fields = 0
    field_presence = {field: 0 for field in required_fields}
    all_fields_seen = set()

    with open(passages_file, encoding="utf-8") as f:
        for line in f:
            if not line.strip():
                continue
            try:
                passage = json.loads(line)
                total_passages += 1

                passage_metadata = passage.get("metadata", {})
                passage_fields = set(passage_metadata.keys())
                all_fields_seen.update(passage_fields)

                # Check if passage has all required fields
                has_all = all(field in passage_fields for field in required_fields)
                if has_all:
                    passages_with_all_fields += 1

                # Count individual field presence
                for field in required_fields:
                    if field in passage_fields:
                        field_presence[field] += 1
            except json.JSONDecodeError:
                continue

    # Calculate percentages
    coverage_percentage = (passages_with_all_fields / total_passages * 100) if total_passages > 0 else 0.0
    field_coverage = {
        field: (count / total_passages * 100) if total_passages > 0 else 0.0
        for field, count in field_presence.items()
    }

    # Find missing fields (fields that don't appear in ANY passage)
    missing_fields = [field for field in required_fields if field not in all_fields_seen]

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields
    }

